// Time:  O(n)
// Space: O(n)

class Solution {
public:
    bool canFormArray(vector<int>& arr, vector<vector<int>>& pieces) {
        unordered_map<int, int> lookup;
        for (int i = 0; i < size(pieces); ++i) {
            lookup[pieces[i][0]] = i;
        }
        for (int i = 0; i < size(arr);) {
            if (!lookup.count(arr[i])) {
                return false;
            }
            for (const auto& c : pieces[lookup[arr[i]]]) {
                if (i == size(arr) || arr[i] != c) {
                    return false;
                }
                ++i;
            }
        }
        return true;
    }
};

# Time:  O(n)
# Space: O(n)

class Solution(object):
    def canFormArray(self, arr, pieces):
        """
        :type arr: List[int]
        :type pieces: List[List[int]]
        :rtype: bool
        """
        lookup = {x[0]: i for i, x in enumerate(pieces)}
        i = 0
        while i < len(arr): 
            if arr[i] not in lookup:
                return False
            for c in pieces[lookup[arr[i]]]:
                if i == len(arr) or arr[i] != c:
                    return False
                i += 1
        return True
